// --- dbConnection.js ---
// This variable is trapped in the Module Scope.
// The rest of the app cannot see or modify it.
const dbPassword = 'super_secret_123';

export function connectToDatabase() {
  // The function can see it because of Lexical Scope!
  console.log('Connecting with password: ' + dbPassword);
}


// --- main.js ---
import { connectToDatabase } from './dbConnection.js';

connectToDatabase(); // Works perfectly

//  ReferenceError: dbPassword is not defined
console.log(dbPassword);

